24:async function findPreviewDependencies(groupId, userId, couponCode, channelCode) {
25:  const [user, group, policy, coupon, channel, membership] = await Promise.all([
26:    prisma.user.findUnique({
27:      where: { id: userId },
28:      include: { profile: true },
29:    }),
30:    prisma.group.findUnique({
31:      where: { id: groupId },
32:    }),
33:    prisma.groupPermissionPolicy.findUnique({
34:      where: { groupId },
35:    }),
36:    couponCode
37:      ? prisma.coupon.findUnique({
38:          where: { code: couponCode },
39:        })
40:      : Promise.resolve(null),
41:    channelCode
42:      ? prisma.promotionChannel.findUnique({
43:          where: { code: channelCode },
44:        })
45:      : Promise.resolve(null),
46:    prisma.groupMember.findUnique({
47:      where: {
48:        groupId_userId: {
49:          groupId,
50:          userId,
51:        },
52:      },
53:    }),
54:  ]);
55:
56:  const matchedCoupon = coupon && coupon.groupId === groupId ? coupon : null;
57:  const matchedChannel = channel && channel.groupId === groupId ? channel : null;
58:
59:  return { user, group, policy, coupon: matchedCoupon, channel: matchedChannel, membership };
60:}
