62:async function buildPreview(groupId, userId, couponCode, channelCode) {
63:  const { user, group, policy, coupon, channel, membership } =
64:    await findPreviewDependencies(groupId, userId, couponCode, channelCode);
65:
66:  if (!user || !user.profile) {
67:    return { statusCode: 404, payload: { ok: false, message: "用户不存在" } };
68:  }
