74:  const baseAmount = toMoneyNumber(group.priceAmount);
75:  const discountAmount = coupon ? toMoneyNumber(coupon.amount) : 0;
76:  const originalAmount = toMoneyNumber(group.originalPriceAmount);
77:  const payableAmount = Math.max(baseAmount - discountAmount, 0);
78:  const durationDays =
79:    group.billingPeriod === "YEAR"
80:      ? 365
81:      : group.billingPeriod === "QUARTER"
82:        ? 90
83:        : group.billingPeriod === "MONTH"
84:          ? 30
85:          : 3650;
86:
87:  return {
88:    statusCode: 200,
89:    payload: {
90:      ok: true,
91:      data: {
92:        user: {
93:          id: user.id,
94:          nickname: user.profile.nickname,
95:        },
96:        group: {
97:          id: group.id,
98:          name: group.name,
99:          intro: group.intro || "",
100:          joinType: group.joinType,
101:          status: group.status,
102:        },
103:        policy: {
104:          allowJoin: policy.allowJoin,
105:          needExamine: policy.needExamine,
106:          allowPreview: policy.allowPreview,
107:          allowSearch: policy.allowSearch,
108:        },
109:        pricing: {
110:          planId: group.id,
111:          billingPeriod: group.billingPeriod,
112:          durationDays,
113:          originalAmount: Math.round(originalAmount * 100),
114:          payableAmount: Math.round(payableAmount * 100),
115:        },
116:        coupon: coupon
117:          ? {
118:              id: coupon.id,
119:              code: coupon.code,
120:              name: coupon.name,
121:              discountAmount: Math.round(toMoneyNumber(coupon.amount) * 100),
