99:async function getCurrentViewer(sessionToken, userId) {
100:  if (sessionToken) {
101:    const session = await prisma.authSession.findUnique({
102:      where: { sessionToken },
103:      include: {
104:        user: {
105:          include: {
106:            profile: true,
107:          },
108:        },
109:      },
110:    });
111:
112:    if (session && session.status === "ACTIVE" && session.expiresAt.getTime() > Date.now()) {
113:      return {
114:        id: session.userId,
115:        profile: session.user.profile || null,
116:      };
117:    }
118:  }
119:
120:  if (userId) {
121:    const user = await prisma.user.findUnique({
122:      where: { id: userId },
123:      include: { profile: true },
124:    });
125:    if (user) {
126:      return {
127:        id: user.id,
128:        profile: user.profile || null,
129:      };
130:    }
131:  }
132:
133:  return null;
134:}
