157:function membershipIsActive(membership) {
158:  if (!membership) {
159:    return false;
160:  }
161:
162:  if (membership.status !== "ACTIVE") {
163:    return false;
164:  }
165:
166:  if (!membership.expireAt) {
167:    return true;
168:  }
169:
170:  return new Date(membership.expireAt).getTime() > Date.now();
171:}
