173:function extractPostCover(post) {
174:  const attachments = Array.isArray(post.attachments) ? post.attachments : [];
175:
176:  for (const item of attachments) {
177:    if (typeof item === "string" && /^https?:\/\//.test(item.trim())) {
178:      return item.trim();
179:    }
180:
181:    if (item && typeof item === "object" && typeof item.url === "string" && /^https?:\/\//.test(item.url.trim())) {
182:      return item.url.trim();
183:    }
184:  }
185:
186:  const metadata = post.metadata && typeof post.metadata === "object" ? post.metadata : {};
187:  const metadataImages = Array.isArray(metadata.images) ? metadata.images : [];
188:
189:  for (const item of metadataImages) {
190:    if (typeof item === "string" && /^https?:\/\//.test(item.trim())) {
191:      return item.trim();
192:    }
193:  }
194:
195:  if (post.group) {
196:    return post.group.coverUrl || post.group.avatarUrl || "";
197:  }
198:
199:  return "";
200:}
