const fs = require('fs');
const path = require('path');

const root = 'backend';
const schema = fs.readFileSync(path.join(root, 'prisma', 'schema.prisma'), 'utf8');
const modelNames = [...schema.matchAll(/"'^model'"\\s+(\\w+)\\s+\\{/gm)].map((m) => m[1]);
const toCamel = (name) => name.charAt(0).toLowerCase() + name.slice(1);
const files = [
  path.join(root, 'src', 'services', 'authService.js'),
  path.join(root, 'src', 'services', 'planetService.js'),
  path.join(root, 'src', 'services', 'joinFlowService.js'),
  path.join(root, 'src', 'services', 'contentService.js'),
  path.join(root, 'scripts', 'deleteGroup.js'),
  path.join(root, 'scripts', 'seedDemoData.js'),
  path.join(root, 'scripts', 'verifyJoinFlow.js'),
  path.join(root, 'src', 'db', 'seedDemoData.js')
];

const result = {};
for (const model of modelNames) {
  const token = toCamel(model);
  result[model] = [];
  for (const file of files) {
    const text = fs.existsSync(file) ? fs.readFileSync(file, 'utf8') : '';
    const regex = new RegExp("'`'"\\\\b(?:prisma|tx)\\\\."'${token}'"\\\\b"'`, '"'g');
    if (regex.test(text)) {
      result[model].push(file.replace(/\\\\/g, '/'));
    }
  }
}
console.log(JSON.stringify(result, null, 2));
